// The four ensures-foralls have auto-triggers `self.get_X(k)` that bind a
// different `self` per run, so on its own z3 never lines up post1 and
// post2 at the same key. Re-assert each forall *per side* with explicit
// triggers on `post1_self_.get_X(...)` / `post2_self_.get_X(...)`, so the
// instances we instantiate at below are guaranteed to fire.
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) ==>
        post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    post2_self_.proc_dom().contains(p_ptr) ==>
        post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

assert(forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    post1_self_.thread_dom().contains(t_ptr) ==>
        post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger post2_self_.get_thread(t_ptr)]
    post2_self_.thread_dom().contains(t_ptr) ==>
        post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));

assert(forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) ==>
        post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr) ==>
        post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));

assert(forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr) && c_ptr != container_ptr ==>
        post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    post2_self_.container_dom().contains(c_ptr) && c_ptr != container_ptr ==>
        post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));

// Domain extensional equality: post1 and post2 each match pre's dom.
assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom());
assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
assert(post1_self_.endpoint_perms@.dom() =~= post2_self_.endpoint_perms@.dom());

// Pointwise: at every key, post1's PointsTo equals post2's. We rely on
// (a) `wf()` giving `addr() == k` and `is_init()` for both posts, and
// (b) the per-run forall ensures (just re-asserted) pinning the inline
// spec `spec_get_X(k) = &perm_map@[k].value()` to `pre`'s value.
assert forall|p_ptr: ProcPtr|
    post1_self_.process_perms@.dom().contains(p_ptr) implies
        post1_self_.process_perms@[p_ptr] == post2_self_.process_perms@[p_ptr] by {
    assert(post1_self_.process_perms@[p_ptr].addr() == p_ptr);
    assert(post2_self_.process_perms@[p_ptr].addr() == p_ptr);
    assert(post1_self_.process_perms@[p_ptr].is_init());
    assert(post2_self_.process_perms@[p_ptr].is_init());
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

assert forall|t_ptr: ThreadPtr|
    post1_self_.thread_perms@.dom().contains(t_ptr) implies
        post1_self_.thread_perms@[t_ptr] == post2_self_.thread_perms@[t_ptr] by {
    assert(post1_self_.thread_perms@[t_ptr].addr() == t_ptr);
    assert(post2_self_.thread_perms@[t_ptr].addr() == t_ptr);
    assert(post1_self_.thread_perms@[t_ptr].is_init());
    assert(post2_self_.thread_perms@[t_ptr].is_init());
    assert(post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
    assert(post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
}

assert forall|e_ptr: EndpointPtr|
    post1_self_.endpoint_perms@.dom().contains(e_ptr) implies
        post1_self_.endpoint_perms@[e_ptr] == post2_self_.endpoint_perms@[e_ptr] by {
    assert(post1_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
    assert(post2_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
    assert(post1_self_.endpoint_perms@[e_ptr].is_init());
    assert(post2_self_.endpoint_perms@[e_ptr].is_init());
    assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
    assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
}

// container_perms needs a case split on `c_ptr == container_ptr`:
//   * `c_ptr != container_ptr`: both posts equal pre via the foralls.
//   * `c_ptr == container_ptr`: every Container field has an unconditional
//     pinning ensures (quota = pre.quota.spec_set_mem_4k(new_quota), all
//     other listed fields =~= pre's), so post1 and post2 agree pointwise.
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_perms@.dom().contains(c_ptr) implies
        post1_self_.container_perms@[c_ptr] == post2_self_.container_perms@[c_ptr] by {
    assert(post1_self_.container_perms@[c_ptr].addr() == c_ptr);
    assert(post2_self_.container_perms@[c_ptr].addr() == c_ptr);
    assert(post1_self_.container_perms@[c_ptr].is_init());
    assert(post2_self_.container_perms@[c_ptr].is_init());
    if c_ptr == container_ptr {
        // quota is pinned to `pre.quota.spec_set_mem_4k(new_quota)` for both
        // posts; spec_set_mem_4k is a pure spec-fn so both yield the same value.
        assert(post1_self_.get_container(container_ptr).quota
            =~= pre_self_.get_container(container_ptr).quota.spec_set_mem_4k(new_quota));
        assert(post2_self_.get_container(container_ptr).quota
            =~= pre_self_.get_container(container_ptr).quota.spec_set_mem_4k(new_quota));
        assert(post1_self_.get_container(container_ptr).quota
            =~= post2_self_.get_container(container_ptr).quota);
        // Every other field is pinned to `pre`'s via an unconditional ensures.
        assert(post1_self_.get_container(container_ptr).owned_procs
            =~= post2_self_.get_container(container_ptr).owned_procs);
        assert(post1_self_.get_container(container_ptr).parent
            =~= post2_self_.get_container(container_ptr).parent);
        assert(post1_self_.get_container(container_ptr).parent_rev_ptr
            =~= post2_self_.get_container(container_ptr).parent_rev_ptr);
        assert(post1_self_.get_container(container_ptr).children
            =~= post2_self_.get_container(container_ptr).children);
        assert(post1_self_.get_container(container_ptr).owned_endpoints
            =~= post2_self_.get_container(container_ptr).owned_endpoints);
        assert(post1_self_.get_container(container_ptr).owned_threads
            =~= post2_self_.get_container(container_ptr).owned_threads);
        assert(post1_self_.get_container(container_ptr).owned_cpus
            =~= post2_self_.get_container(container_ptr).owned_cpus);
        assert(post1_self_.get_container(container_ptr).scheduler
            =~= post2_self_.get_container(container_ptr).scheduler);
        assert(post1_self_.get_container(container_ptr).depth
            =~= post2_self_.get_container(container_ptr).depth);
        assert(post1_self_.get_container(container_ptr).uppertree_seq
            =~= post2_self_.get_container(container_ptr).uppertree_seq);
        assert(post1_self_.get_container(container_ptr).subtree_set
            =~= post2_self_.get_container(container_ptr).subtree_set);
        assert(post1_self_.get_container(container_ptr).root_process
            =~= post2_self_.get_container(container_ptr).root_process);
    } else {
        assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    }
}

// Lift the pointwise PointsTo equalities to map extensional equality, which
// is what `det_set_container_mem_quota_mem_4k_equal` reads on `(_perms)@`.
assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);
assert(post1_self_.thread_perms@ =~= post2_self_.thread_perms@);
assert(post1_self_.endpoint_perms@ =~= post2_self_.endpoint_perms@);
assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);
